// FIX: el SQL alias la descripción como `descripcion_corta`, no `descripcion`.
// Antes el catálogo mandaba Keywords vacío al LLM.
const rows = $input.all();
const descripcion = $('When Executed by Another Workflow').first().json.descripcion;

const catalogo = rows.map(r => 
  `ID: ${r.json.id} | [${r.json.categoria}] ${r.json.flujo} | Keywords: ${r.json.descripcion_corta ? r.json.descripcion_corta.substring(0, 200) : ''}`
).join('\n');

return [{ json: { catalogo, descripcion, total_flujos: rows.length } }];

// FIX: ahora devuelve procedimiento_completo (árbol paso a paso)
// en lugar de descripcion (que ni siquiera era un campo existente).
const idElegido = parseInt($input.first().json.text.trim());
const rows = $('Execute a SQL query2').all();

if (idElegido === 0 || isNaN(idElegido)) {
  return [{ json: { 
    procedimiento: 'No encontré un flujo de soporte que coincida con este problema. Por favor describe mejor el equipo, módulo o síntoma.',
    categoria: 'N/A',
    flujo: 'No identificado',
    multimedia: ''
  }}];
}

const match = rows.find(r => r.json.id === idElegido);

if (!match) {
  return [{ json: { 
    procedimiento: 'No encontré un flujo para este problema.',
    categoria: 'N/A',
    flujo: 'No encontrado',
    multimedia: ''
  }}];
}

return [{ json: { 
  procedimiento: match.json.procedimiento_completo || match.json.descripcion_corta || 'Sin procedimiento registrado',
  categoria: match.json.categoria,
  flujo: match.json.flujo,
  multimedia: match.json.multimedia_disponible || 'Sin multimedia registrada'
}}];
